function getEmbeddedMobilePlanConfig(sourceBlocks: Block[]): PagePlanConfig | null {
  const carrier = sourceBlocks.find((block) => !!(block?.props as { pagePlanConfigMobile?: unknown } | undefined)?.pagePlanConfigMobile);
  const rawMobile = (carrier?.props as { pagePlanConfigMobile?: unknown } | undefined)?.pagePlanConfigMobile;
  if (!rawMobile) return null;
  const cloned = cloneBlocks(sourceBlocks);
  const carrierIndex = cloned.findIndex((block) => !!(block?.props as { pagePlanConfigMobile?: unknown } | undefined)?.pagePlanConfigMobile);
  if (carrierIndex >= 0) {
    cloned[carrierIndex] = {
      ...cloned[carrierIndex],
      props: {
        ...cloned[carrierIndex].props,
        pagePlanConfig: rawMobile as never,
      } as never,
    } as Block;
    delete (cloned[carrierIndex].props as { pagePlanConfigMobile?: unknown }).pagePlanConfigMobile;
  }
  return getPagePlanConfigFromBlocks(cloned);
}

function scaleValue(value: unknown, min?: number) {
  if (typeof value !== "number" || !Number.isFinite(value)) return value;
  const scaled = Math.round(value * MOBILE_SIZE_SCALE);
  return typeof min === "number" ? Math.max(min, scaled) : scaled;
}

function adaptBlockForMobile(block: Block): Block {
  const next = cloneBlocks([block])[0];
  const props = { ...(next.props as Record<string, unknown>) };
  const originalWidth =
    typeof props.blockWidth === "number" && Number.isFinite(props.blockWidth) ? Math.max(1, Math.round(props.blockWidth)) : undefined;
  const scaledWidth = typeof originalWidth === "number" ? Math.round(originalWidth * MOBILE_SIZE_SCALE) : undefined;
  const fittedWidth =
    typeof scaledWidth === "number"
      ? Math.max(120, Math.min(MOBILE_CONTENT_MAX_WIDTH, scaledWidth))
      : undefined;
  props.blockWidth = fittedWidth;
  props.blockHeight = scaleValue(props.blockHeight, 80);
  const scaledOffsetX = scaleValue(props.blockOffsetX);
  if (typeof scaledOffsetX === "number") {
    const maxX = Math.max(0, MOBILE_CONTENT_MAX_WIDTH - (typeof fittedWidth === "number" ? fittedWidth : MOBILE_CONTENT_MAX_WIDTH)) + MOBILE_SAFE_PADDING;
    const minX = -MOBILE_SAFE_PADDING;
    props.blockOffsetX = Math.max(minX, Math.min(maxX, scaledOffsetX));
  } else {
    props.blockOffsetX = scaledOffsetX;
  }
  props.blockOffsetY = scaleValue(props.blockOffsetY);
  props.fontSize = scaleValue(props.fontSize, 10);
  const galleryFrameWidth = scaleValue(props.galleryFrameWidth, 120);
  props.galleryFrameWidth =
    typeof galleryFrameWidth === "number" ? Math.min(MOBILE_CONTENT_MAX_WIDTH, galleryFrameWidth) : galleryFrameWidth;
  props.galleryFrameHeight = scaleValue(props.galleryFrameHeight, 80);
  if (Array.isArray(props.commonTextBoxes)) {
    props.commonTextBoxes = props.commonTextBoxes.map((item) => {
      const box = { ...(item as Record<string, unknown>) };
      box.x = scaleValue(box.x);
      box.y = scaleValue(box.y);
      box.width = scaleValue(box.width, 60);
      box.height = scaleValue(box.height, 40);
      return box;
    });
  }
  next.props = props as never;
  return next;
}

function fitBlocksIntoMobileWidth(blocks: Block[]): Block[] {
  if (blocks.length === 0) return blocks;
  const adapted = cloneBlocks(blocks);
  const metrics = adapted.map((block) => {
    const props = block.props as Record<string, unknown>;
    const x =
      typeof props.blockOffsetX === "number" && Number.isFinite(props.blockOffsetX)
        ? Math.round(props.blockOffsetX)
        : 0;
    const width =
      typeof props.blockWidth === "number" && Number.isFinite(props.blockWidth)
        ? Math.max(120, Math.round(props.blockWidth))
        : MOBILE_CONTENT_MAX_WIDTH;
    return { x, width, right: x + width };
  });
  const minLeft = Math.min(...metrics.map((item) => item.x));
  const maxRight = Math.max(...metrics.map((item) => item.right));
  const contentWidth = Math.max(1, maxRight - minLeft);
  const availableWidth = MOBILE_CONTENT_MAX_WIDTH;
  const scale = contentWidth > availableWidth ? availableWidth / contentWidth : 1;

  return adapted.map((block, idx) => {
    const props = { ...(block.props as Record<string, unknown>) };
    const originalX = metrics[idx].x;
    const originalWidth = metrics[idx].width;
    const normalizedX = Math.round((originalX - minLeft) * scale);
    const normalizedWidth = Math.max(120, Math.min(availableWidth, Math.round(originalWidth * scale)));
    props.blockOffsetX = normalizedX;
    props.blockWidth = normalizedWidth;
    if (typeof props.fontSize === "number" && Number.isFinite(props.fontSize)) {
      props.fontSize = Math.max(10, Math.round(Number(props.fontSize) * scale));
    }
    if (typeof props.galleryFrameWidth === "number" && Number.isFinite(props.galleryFrameWidth)) {
      props.galleryFrameWidth = Math.max(120, Math.min(availableWidth, Math.round(Number(props.galleryFrameWidth) * scale)));
    }
    if (Array.isArray(props.commonTextBoxes)) {
      props.commonTextBoxes = props.commonTextBoxes.map((item) => {
        const box = { ...(item as Record<string, unknown>) };
        if (typeof box.x === "number" && Number.isFinite(box.x)) box.x = Math.round(Number(box.x) * scale);
        if (typeof box.width === "number" && Number.isFinite(box.width)) {
          box.width = Math.max(60, Math.round(Number(box.width) * scale));
        }
        if (typeof box.height === "number" && Number.isFinite(box.height)) {
          box.height = Math.max(40, Math.round(Number(box.height) * scale));
        }
        return box;
      });
    }
    return {
      ...block,
      props: props as never,
    } as Block;
  });
}

function adaptPlanConfigForMobile(config: PagePlanConfig): PagePlanConfig {
  return {
    ...config,
    plans: config.plans.map((plan) => ({
      ...plan,
      blocks: fitBlocksIntoMobileWidth(plan.blocks.map(adaptBlockForMobile)),
      pages: plan.pages.map((page) => ({
        ...page,
        blocks: fitBlocksIntoMobileWidth(page.blocks.map(adaptBlockForMobile)),
      })),
    })),
  };
}

function getPreviewColSpan(itemClass: string) {
  const match = itemClass.match(/col-span-(\d+)/);
  const value = Number(match?.[1] ?? 4);
  if (!Number.isFinite(value)) return 4;
  return Math.max(1, Math.min(12, value));
}

function getPreviewBlockHeight(layout: GalleryCardLayout, minHeight: number, maxHeight: number) {
  if (layout.frameStyle.aspectRatio) return undefined;
  const height = typeof layout.frameStyle.height === "number" ? layout.frameStyle.height : minHeight;
  if (maxHeight <= minHeight) return 12;
  const ratio = (height - minHeight) / (maxHeight - minHeight);
  return Math.round(10 + ratio * 8);
}

function getCustomPreviewBlankSpans(row: { align: GalleryRowAlign; items: Array<{ span: number }> }) {
  const used = row.items.reduce((sum, item) => sum + Math.max(0, Math.min(12, Math.round(item.span))), 0);
  const remain = Math.max(0, 12 - used);
  if (row.align === "right") return { leading: remain, trailing: 0 };
  if (row.align === "center") {
    const leading = Math.floor(remain / 2);
    return { leading, trailing: remain - leading };
  }
  return { leading: 0, trailing: remain };
}

function getGalleryLayoutLabel(preset: GalleryLayoutPreset) {
  if (preset === "three-wide") return "三列";
  if (preset === "two-wide") return "双列";
  if (preset === "single-wide") return "通栏";
  if (preset === "three-square") return "三列等宽";
  if (preset === "mosaic") return "拼接";
  return "自定义样式";
}

function getFirstNavBlock(blocks: Block[]) {
  return blocks.find((item) => item.type === "nav") ?? null;
}

function stripNavBlocks(blocks: Block[]) {
  return blocks.filter((item) => item.type !== "nav");
}

function hasNavBlock(blocks: Block[]) {
  return blocks.some((item) => item.type === "nav");
}

function getDefaultSelectedBlockIdForPage(blocks: Block[]) {
  return blocks.find((item) => item.type !== "nav")?.id ?? "";
}

function getNavSyncKey(blocks: Block[]) {
  const nav = getFirstNavBlock(blocks);
  if (!nav || nav.type !== "nav") return "";
  const items = Array.isArray(nav.props.navItems)
    ? nav.props.navItems.map((item) => ({
        pageId: typeof item?.pageId === "string" ? item.pageId : "",
        label: typeof item?.label === "string" ? item.label : "",
      }))
    : [];
  return JSON.stringify(items);
}

const MERCHANT_ONBOARDING_BLOCKS: Block[] = (() => {
  const navBlock = homeBlocks.find((item) => item.type === "nav");
  if (navBlock) return cloneBlocks([navBlock]);
  return [
    {
      id: "b-nav",
      type: "nav",
      props: {
        heading: "页面导航",
        navOrientation: "horizontal",
        navItems: [{ id: "b-nav-item-1", label: "页面1", pageId: "page-1" }],
      },
    },
  ];
})();

function isCommonCanvasBlockType(type: Block["type"]): type is "common" {
  return type === "common";
}

function getBlockMinWidth(type: Block["type"]) {
  return type === "button" ? BUTTON_BLOCK_MIN_WIDTH : MIN_BLOCK_WIDTH;
}

function getBlockMinHeight(type: Block["type"]) {
  return type === "button" ? BUTTON_BLOCK_MIN_HEIGHT : MIN_BLOCK_HEIGHT;
}

function normalizeBlockWidth(value?: number, type: Block["type"] = "common") {
  if (typeof value !== "number" || !Number.isFinite(value)) return undefined;
  return Math.max(getBlockMinWidth(type), Math.round(value));
}

function normalizeBlockHeight(value?: number, type: Block["type"] = "common") {
  if (typeof value !== "number" || !Number.isFinite(value)) return undefined;
  return Math.max(getBlockMinHeight(type), Math.round(value));
}

function getBlockTypeLabel(type: string) {
  return (BLOCK_TYPE_LABELS as Record<string, string>)[type] ?? type;
}

function toPlainText(value: string | undefined, fallback = "") {
  const source = (value ?? "").trim();
  if (!source) return fallback;
  const noTags = source
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<[^>]*>/g, "")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'");
  return noTags.trim() || fallback;
}

function getThemeCopyKeysForBlockType(type: Block["type"]) {
  if (type === "product") return PRODUCT_THEME_COPY_KEYS;
  if (type === "merchant-list") return MERCHANT_LIST_THEME_COPY_KEYS;
  return [] as const;
}

function pickDefinedProps(
  source: Record<string, unknown> | undefined,
  keys: readonly string[],
): Record<string, unknown> {
  const next: Record<string, unknown> = {};
  if (!source) return next;
  keys.forEach((key) => {
    if (typeof source[key] !== "undefined") {
      next[key] = source[key];
    }
  });
  return next;
}

function buildPageCopyItemIdForBlock(blockId: string): `block:${string}` {
  return `block:${blockId}`;
}

function buildPageCopyBlockLabel(block: Block, index: number) {
  const props = block.props as Record<string, unknown>;
  const summary = [
    toPlainText(typeof props.heading === "string" ? props.heading : "", ""),
    toPlainText(typeof props.title === "string" ? props.title : "", ""),
    toPlainText(typeof props.buttonLabel === "string" ? props.buttonLabel : "", ""),
    toPlainText(typeof props.phone === "string" ? props.phone : "", ""),
    toPlainText(typeof props.address === "string" ? props.address : "", ""),
    toPlainText(typeof props.text === "string" ? props.text : "", ""),
  ]
    .map((item) => item.trim())
    .find(Boolean);
  const clippedSummary =
    summary && summary.length > 22
      ? `${summary.slice(0, 22).trimEnd()}...`
      : summary;
  return `${index + 1}. ${getBlockTypeLabel(block.type)}${clippedSummary ? ` · ${clippedSummary}` : ""}`;
}

function hasVisibleRichText(value?: string) {
  const raw = String(value ?? "");
  if (!raw.trim()) return false;
  const stripped = raw
    .replace(/<[^>]*>/g, " ")
    .replace(/&nbsp;/gi, " ")
    .trim();
  return stripped.length > 0;
}

function toRgba(hex: string, alpha: number) {
  const value = /^#([0-9a-fA-F]{6})$/.test(hex) ? hex : "#ffffff";
  const r = Number.parseInt(value.slice(1, 3), 16);
  const g = Number.parseInt(value.slice(3, 5), 16);
  const b = Number.parseInt(value.slice(5, 7), 16);
  return `rgba(${r}, ${g}, ${b}, ${Math.max(0, Math.min(1, alpha)).toFixed(3)})`;
}

function normalizeHexColor(value: string) {
  const trimmed = value.trim();
  return /^#([0-9a-fA-F]{6})$/.test(trimmed) ? trimmed.toLowerCase() : null;
}

function buildLinearGradient(direction: GradientDirection, start: string, end: string) {
  const startHex = normalizeHexColor(start) ?? "#ffffff";
  const endHex = normalizeHexColor(end) ?? "#000000";
  return `linear-gradient(${direction}, ${startHex} 0%, ${endHex} 100%)`;
}

function parseGradientValue(value: string | undefined) {
  const raw = (value ?? "").trim();
  const solidHex = normalizeHexColor(raw);
  if (solidHex) {
    return {
      mode: "solid" as const,
      solidColor: solidHex,
      startColor: solidHex,
      endColor: "#000000",
      direction: "to right" as GradientDirection,
    };
  }

  const gradientMatch = raw.match(
    /^linear-gradient\(\s*(to\s+(?:left|right|top|bottom)(?:\s+(?:left|right|top|bottom))?)\s*,\s*(#[0-9a-fA-F]{6})(?:\s+\d+%?)?\s*,\s*(#[0-9a-fA-F]{6})(?:\s+\d+%?)?\s*\)$/i,
  );
  if (gradientMatch) {
    const parsedDirection = gradientMatch[1].toLowerCase() as GradientDirection;
    const direction = GRADIENT_DIRECTION_OPTIONS.some((item) => item.value === parsedDirection)
      ? parsedDirection
      : "to right";
    return {
      mode: "gradient" as const,
      solidColor: "#ffffff",
      startColor: gradientMatch[2].toLowerCase(),
      endColor: gradientMatch[3].toLowerCase(),
      direction,
    };
  }

  return {
    mode: "solid" as const,
    solidColor: "#ffffff",
    startColor: "#ffffff",
    endColor: "#000000",
    direction: "to right" as GradientDirection,
  };
}

function normalizeRecentColorToken(value: string) {
  const hex = normalizeHexColor(value);
  if (hex) return hex;
  const trimmed = value.trim();
  if (/^linear-gradient\(/i.test(trimmed)) {
    return trimmed;
  }
  return null;
}

function isGradientToken(value: string) {
  return /^linear-gradient\(/i.test(value.trim());
}

function normalizeNavBorderColor(value: string, fallback: string) {
  const trimmed = value.trim();
  if (/^#([0-9a-fA-F]{6})$/.test(trimmed)) return trimmed;
  const firstHex = trimmed.match(/#([0-9a-fA-F]{6})/);
  if (firstHex) return `#${firstHex[1]}`;
  return fallback;
}

function isEditorTypingTarget(target: EventTarget | null) {
  if (!(target instanceof HTMLElement)) return false;
  if (target.isContentEditable) return true;
  if (target.closest('[contenteditable="true"]')) return true;
  return (
    target instanceof HTMLInputElement ||
    target instanceof HTMLTextAreaElement ||
    target instanceof HTMLSelectElement
  );
}

function isEditorToolbarInteractionTarget(target: EventTarget | null) {
  if (!(target instanceof HTMLElement)) return false;
  if (target.closest("[data-editor-overlay]")) return true;
  return false;
}

function gradientWithOpacity(value: string, opacity: number) {
  const alpha = Math.max(0, Math.min(1, opacity));
  let next = value.replace(/#([0-9a-fA-F]{6})/g, (match, hex: string) => {
    const r = Number.parseInt(hex.slice(0, 2), 16);
    const g = Number.parseInt(hex.slice(2, 4), 16);
    const b = Number.parseInt(hex.slice(4, 6), 16);
    if (!Number.isFinite(r) || !Number.isFinite(g) || !Number.isFinite(b)) return match;
    return `rgba(${r}, ${g}, ${b}, ${alpha.toFixed(3)})`;
  });
  next = next.replace(/rgba?\(([^)]+)\)/gi, (match, content: string) => {
    const parts = content.split(",").map((item) => item.trim());
    const r = Number(parts[0]);
    const g = Number(parts[1]);
    const b = Number(parts[2]);
    if (!Number.isFinite(r) || !Number.isFinite(g) || !Number.isFinite(b)) return match;
    return `rgba(${Math.round(r)}, ${Math.round(g)}, ${Math.round(b)}, ${alpha.toFixed(3)})`;
  });
  return next;
}

function getColorLayerStyle(value: string, opacity: number) {
  const trimmed = value.trim();
  if (isGradientToken(trimmed)) {
    return {
      backgroundImage: opacity < 1 ? gradientWithOpacity(trimmed, opacity) : trimmed,
    };
  }
  return {
    backgroundColor: toRgba(trimmed, opacity),
  };
}

type MerchantCardIndustryStyleConfig = {
  bgColor?: string;
  bgOpacity?: number;
  borderStyle?: BlockBorderStyle;
  borderColor?: string;
};

const DEFAULT_MERCHANT_CARD_TEXT_LAYOUT: Record<MerchantCardTextRole, { x: number; y: number }> = {
  name: { x: 0, y: 0 },
  industry: { x: 0, y: 30 },
  domain: { x: 0, y: 52 },
};

function resolveMerchantCardTextPosition(layout: MerchantCardTextLayoutConfig | undefined, role: MerchantCardTextRole) {
  const fallback = DEFAULT_MERCHANT_CARD_TEXT_LAYOUT[role];
  const current = layout?.[role] ?? {};
  const x = typeof current.x === "number" && Number.isFinite(current.x) ? Math.max(0, Math.round(current.x)) : fallback.x;
  const y = typeof current.y === "number" && Number.isFinite(current.y) ? Math.max(0, Math.round(current.y)) : fallback.y;
  return { x, y };
}

function normalizeMerchantCardTextLayoutConfig(layout: MerchantCardTextLayoutConfig | undefined): MerchantCardTextLayoutConfig {
  return {
    name: resolveMerchantCardTextPosition(layout, "name"),
    industry: resolveMerchantCardTextPosition(layout, "industry"),
    domain: resolveMerchantCardTextPosition(layout, "domain"),
  };
}

function resolveMerchantIndustryCardStyle(
  stylesByIndustry: Partial<Record<MerchantIndustryTabIndustry, MerchantCardIndustryStyleConfig>> | undefined,
  targetIndustry: MerchantIndustryTabIndustry,
  legacy: {
    bgColor: string;
    bgOpacity: number;
    borderStyle: BlockBorderStyle;
    borderColor: string;
  },
) {
  const scoped = stylesByIndustry?.[targetIndustry];
  const fallback = stylesByIndustry?.all;
  const candidate = scoped ?? fallback;
  if (!candidate) return legacy;
  return {
    bgColor: (candidate.bgColor ?? "").trim() || legacy.bgColor,
    bgOpacity:
      typeof candidate.bgOpacity === "number" && Number.isFinite(candidate.bgOpacity)
        ? Math.max(0, Math.min(1, candidate.bgOpacity))
        : legacy.bgOpacity,
    borderStyle: (candidate.borderStyle ?? legacy.borderStyle) as BlockBorderStyle,
    borderColor: (candidate.borderColor ?? "").trim() || legacy.borderColor,
  };
}

function buildTypographyInlineStyle(style: TypographyEditableProps | undefined): Record<string, string | number> {
  const result: Record<string, string | number> = {};
  const fontFamily = (style?.fontFamily ?? "").trim();
  const fontColor = (style?.fontColor ?? "").trim();
  if (fontFamily) result.fontFamily = fontFamily;
  if (typeof style?.fontSize === "number" && Number.isFinite(style.fontSize) && style.fontSize > 0) {
    result.fontSize = Math.max(8, Math.min(120, style.fontSize));
  }
  if (style?.fontWeight) result.fontWeight = style.fontWeight;
  if (style?.fontStyle) result.fontStyle = style.fontStyle;
  if (style?.textDecoration) result.textDecoration = style.textDecoration;
  if (fontColor) {
    if (isGradientToken(fontColor)) {
      result.backgroundImage = fontColor;
      result.backgroundClip = "text";
      result.WebkitBackgroundClip = "text";
      result.color = "transparent";
    } else {
      result.color = fontColor;
    }
  }
  return result;
}

function loadRecentColors(): string[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(RECENT_COLORS_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((item) => (typeof item === "string" ? normalizeRecentColorToken(item) : null))
      .filter((item): item is string => !!item)
      .slice(0, MAX_RECENT_COLORS);
  } catch {
    return [];
  }
}

function isInlineDataImageUrl(value: string) {
  return /^data:image\//i.test(value);
}

function ensureSafeImageUrlSize(value: string | undefined) {
  if (!value) return value;
  if (isInlineDataImageUrl(value) && value.length > MAX_ORIGINAL_IMAGE_DATA_URL_LENGTH) {
    throw new Error("图片数据过大，上传较小图片或使用URL");
  }
  return value;
}

async function fileToDataUrl(file: File): Promise<string> {
  return await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      if (typeof reader.result !== "string") {
        reject(new Error("图片读取失败，请重新选择图片后重试"));
        return;
      }
      resolve(reader.result);
    };
    reader.onerror = () => reject(new Error("图片读取失败，请重新选择图片后重试"));
    reader.readAsDataURL(file);
  });
}

async function fileToChatFileDataUrl(file: File): Promise<string> {
  if (file.size > MAX_CHAT_FILE_BYTES) {
    throw new Error("文件过大，请选择 12MB 以内文件");
  }
  return await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      if (typeof reader.result !== "string") {
        reject(new Error("文件读取失败，请重新选择后重试"));
        return;
      }
      resolve(reader.result);
    };
    reader.onerror = () => reject(new Error("文件读取失败，请重新选择后重试"));
    reader.readAsDataURL(file);
  });
}

async function loadImageFromDataUrl(dataUrl: string): Promise<HTMLImageElement> {
  return await new Promise((resolve, reject) => {
    const image = new Image();
    image.onload = () => resolve(image);
    image.onerror = () => reject(new Error("图片解析失败，请更换图片"));
    image.src = dataUrl;
  });
}

function clamp(value: number, min: number, max: number) {
  return Math.max(min, Math.min(max, value));
}

async function blobToDataUrl(blob: Blob): Promise<string> {
  return await new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(typeof reader.result === "string" ? reader.result : "");
    reader.onerror = () => reject(new Error("图片读取失败，请重新选择图片后重试"));
    reader.readAsDataURL(blob);
  });
}

function estimateDataUrlBytes(dataUrl: string) {
  const base64 = dataUrl.split(",")[1] ?? "";
  if (!base64) {
    return typeof TextEncoder !== "undefined" ? new TextEncoder().encode(dataUrl).length : dataUrl.length;
  }
  return Math.max(0, Math.floor((base64.length * 3) / 4));
}

async function yieldToBrowser() {
  await new Promise<void>((resolve) => {
    if (typeof requestAnimationFrame === "function") {
      requestAnimationFrame(() => resolve());
      return;
    }
    setTimeout(resolve, 0);
  });
}

async function canvasToBlob(canvas: HTMLCanvasElement, type: string, quality: number) {
  return await new Promise<Blob | null>((resolve) => {
    canvas.toBlob((blob) => resolve(blob), type, quality);
  });
}

async function loadImageFromBlob(blob: Blob): Promise<HTMLImageElement> {
  const objectUrl = URL.createObjectURL(blob);
  try {
    return await loadImageFromDataUrl(objectUrl);
  } finally {
    URL.revokeObjectURL(objectUrl);
  }
}

async function compressImageDataUrl(dataUrl: string, options: { maxSide: number; quality: number }): Promise<string> {
  const image = await loadImageFromDataUrl(dataUrl);
  const naturalWidth = image.naturalWidth || image.width;
  const naturalHeight = image.naturalHeight || image.height;
  if (!naturalWidth || !naturalHeight) {
    throw new Error("图片尺寸异常，请更换图片");
  }

  const scale = Math.min(1, options.maxSide / Math.max(naturalWidth, naturalHeight));
  const targetWidth = Math.max(1, Math.round(naturalWidth * scale));
  const targetHeight = Math.max(1, Math.round(naturalHeight * scale));

  const canvas = document.createElement("canvas");
  canvas.width = targetWidth;
  canvas.height = targetHeight;
  const ctx = canvas.getContext("2d");
  if (!ctx) throw new Error("图片处理失败，请重试");

  ctx.drawImage(image, 0, 0, targetWidth, targetHeight);
  return canvas.toDataURL("image/webp", options.quality);
}

function buildInitialImageCompressionPlan(sourceBytes: number, limitBytes: number) {
  const ratio = clamp(limitBytes / Math.max(sourceBytes, 1), 0.05, 1);
  if (ratio >= 0.72) {
    return {
      scale: 1,
      quality: clamp(ratio * 0.96, 0.68, 0.92),
    };
  }
  return {
    scale: clamp(Math.sqrt(ratio / 0.84) * 0.99, 0.16, 1),
    quality: 0.84,
  };
}

function refineImageCompressionPlan(
  previous: { scale: number; quality: number },
  candidateBytes: number,
  limitBytes: number,
) {
  const ratio = clamp(limitBytes / Math.max(candidateBytes, 1), 0.05, 1);
  return {
    scale: clamp(previous.scale * Math.sqrt(ratio) * 0.98, 0.12, 1),
    quality: clamp(Math.min(previous.quality * ratio * 1.04, previous.quality), 0.42, 0.92),
  };
}

async function renderCompressedImageCandidate(
  image: HTMLImageElement,
  scale: number,
  quality: number,
) {
  const targetWidth = Math.max(1, Math.round(image.naturalWidth * scale));
  const targetHeight = Math.max(1, Math.round(image.naturalHeight * scale));
  const canvas = document.createElement("canvas");
  canvas.width = targetWidth;
  canvas.height = targetHeight;
  const context = canvas.getContext("2d");
  if (!context) {
    throw new Error("读取图片失败");
  }
  context.imageSmoothingEnabled = true;
  context.imageSmoothingQuality = "high";
  context.clearRect(0, 0, targetWidth, targetHeight);
  context.drawImage(image, 0, 0, targetWidth, targetHeight);

  const blob = await canvasToBlob(canvas, "image/webp", quality);
  if (blob) {
    return { blob, dataUrl: "", bytes: blob.size };
  }
  const dataUrl = canvas.toDataURL("image/webp", quality);
  return { blob: null, dataUrl, bytes: estimateDataUrlBytes(dataUrl) };
}

async function finalizeCompressedImageCandidate(candidate: {
  blob: Blob | null;
  dataUrl: string;
  bytes: number;
}) {
  return {
    dataUrl: candidate.blob ? await blobToDataUrl(candidate.blob) : candidate.dataUrl,
    bytes: candidate.bytes,
  };
}

async function compressImageFileWithinLimit(
  file: File,
  limitBytes: number,
  options: { maxSide: number; quality: number } = IMAGE_COMPRESSION_OPTIONS.high,
) {
  if (!file.type.startsWith("image/")) {
    throw new Error("请选择图片文件");
  }
  if (file.size > MAX_IMAGE_FILE_BYTES) {
    throw new Error("图片文件过大，请选择 10MB 以内图片");
  }
  const originalBytes = file.size || 0;
  if (originalBytes > 0 && originalBytes <= limitBytes) {
    const dataUrl = await fileToOriginalImageDataUrl(file, options);
    return {
      dataUrl,
      compressed: false,
      bytes: originalBytes || estimateDataUrlBytes(dataUrl),
    };
  }

  const image = await loadImageFromBlob(file);
  let plan = buildInitialImageCompressionPlan(originalBytes || limitBytes + 1, limitBytes);
  let bestCandidate:
    | {
        blob: Blob | null;
        dataUrl: string;
        bytes: number;
      }
    | null = null;

  for (let attempt = 0; attempt < 6; attempt += 1) {
    await yieldToBrowser();
    const candidate = await renderCompressedImageCandidate(image, plan.scale, plan.quality);
    if (!bestCandidate || candidate.bytes < bestCandidate.bytes) {
      bestCandidate = candidate;
    }
    if (candidate.bytes <= limitBytes) {
      const finalized = await finalizeCompressedImageCandidate(candidate);
      return {
        dataUrl: finalized.dataUrl,
        compressed: true,
        bytes: finalized.bytes,
      };
    }
    plan = refineImageCompressionPlan(plan, candidate.bytes, limitBytes);
  }

  if (bestCandidate) {
    const finalized = await finalizeCompressedImageCandidate(bestCandidate);
    return {
      dataUrl: finalized.dataUrl,
      compressed: true,
      bytes: finalized.bytes,
    };
  }

  const originalDataUrl = await fileToOriginalImageDataUrl(file, options);
  return {
    dataUrl: originalDataUrl,
    compressed: false,
    bytes: originalBytes || estimateDataUrlBytes(originalDataUrl),
  };
}

const SUPPORT_SELF_AVATAR_MAX_BYTES = 40 * 1024;
const SUPPORT_SELF_AVATAR_COMPRESSION_STEPS = [
  { maxSide: 384, quality: 0.9 },
  { maxSide: 320, quality: 0.86 },
  { maxSide: 288, quality: 0.82 },
  { maxSide: 256, quality: 0.78 },
  { maxSide: 224, quality: 0.72 },
  { maxSide: 192, quality: 0.66 },
  { maxSide: 160, quality: 0.6 },
  { maxSide: 128, quality: 0.52 },
] as const;

async function compressSupportSelfAvatarFile(file: File) {
  if (file.size > 0 && file.size <= SUPPORT_SELF_AVATAR_MAX_BYTES) {
    return {
      dataUrl: await fileToDataUrl(file),
      bytes: file.size,
    };
  }

  const image = await loadImageFromBlob(file);
  const longestSide = Math.max(image.naturalWidth || image.width, image.naturalHeight || image.height, 1);
  let bestCandidate: { dataUrl: string; bytes: number } | null = null;
  for (const step of SUPPORT_SELF_AVATAR_COMPRESSION_STEPS) {
    await yieldToBrowser();
    const scale = Math.min(1, step.maxSide / longestSide);
    const finalized = await finalizeCompressedImageCandidate(
      await renderCompressedImageCandidate(image, scale, step.quality),
    );
    const nextDataUrl = finalized.dataUrl;
    const nextBytes = finalized.bytes;

    if (!bestCandidate || nextBytes < bestCandidate.bytes) {
      bestCandidate = {
        dataUrl: nextDataUrl,
        bytes: nextBytes,
      };
    }

    if (nextBytes <= SUPPORT_SELF_AVATAR_MAX_BYTES) {
      return {
        dataUrl: nextDataUrl,
        bytes: nextBytes,
      };
    }
  }

  const genericCompressed = await compressImageFileWithinLimit(file, SUPPORT_SELF_AVATAR_MAX_BYTES, {
    maxSide: SUPPORT_SELF_AVATAR_COMPRESSION_STEPS[0].maxSide,
    quality: SUPPORT_SELF_AVATAR_COMPRESSION_STEPS[0].quality,
  });
  if (genericCompressed.bytes <= SUPPORT_SELF_AVATAR_MAX_BYTES) {
    return {
      dataUrl: genericCompressed.dataUrl,
      bytes: genericCompressed.bytes,
    };
  }

  throw new Error(
    bestCandidate
      ? `头像压缩后仍有 ${Math.ceil(bestCandidate.bytes / 1024)}KB，请换一张更小的图片`
      : "头像压缩失败，请换一张更小的图片",
  );
}

async function fileToOriginalImageDataUrl(
  file: File,
  options: { maxSide: number; quality: number } = IMAGE_COMPRESSION_OPTIONS.high,
): Promise<string> {
  if (!file.type.startsWith("image/")) {
    throw new Error("请选择图片文件");
  }
  if (file.size > MAX_IMAGE_FILE_BYTES) {
    throw new Error("图片文件过大，请选择 10MB 以内图片");
  }

  const dataUrl = await fileToDataUrl(file);
  if (dataUrl.length <= MAX_ORIGINAL_IMAGE_DATA_URL_LENGTH) return dataUrl;

  const compressedDataUrl = await compressImageDataUrl(dataUrl, options);
  if (compressedDataUrl.length > MAX_ORIGINAL_IMAGE_DATA_URL_LENGTH) {
    throw new Error("图片过大，更换更小分辨率图");
  }
  return compressedDataUrl;
}

async function fileToOptimizedImageDataUrl(
  file: File,
  options: { maxSide: number; quality: number },
): Promise<string> {
  if (!file.type.startsWith("image/")) {
    throw new Error("请选择图片文件");
  }
  if (file.size > MAX_IMAGE_FILE_BYTES) {
    throw new Error("图片文件过大，请选择 10MB 以内图片");
  }

  const originalDataUrl = await fileToDataUrl(file);
  const compressedDataUrl = await compressImageDataUrl(originalDataUrl, options);
  const candidate = compressedDataUrl.length > 0 && compressedDataUrl.length < originalDataUrl.length
    ? compressedDataUrl
    : originalDataUrl;
  if (candidate.length > MAX_ORIGINAL_IMAGE_DATA_URL_LENGTH) {
    throw new Error("图片过大，更换更小分辨率图");
  }
  return candidate;
}

async function fileToAudioDataUrl(file: File): Promise<string> {
  if (!file.type.startsWith("audio/")) {
    throw new Error("请选择音频文件");
  }
  const dataUrl = await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      if (typeof reader.result !== "string") {
        reject(new Error("音频读取失败，请重试"));
        return;
      }
      resolve(reader.result);
    };
    reader.onerror = () => reject(new Error("音频读取失败，请重试"));
    reader.readAsDataURL(file);
  });
  if (dataUrl.length > MAX_AUDIO_DATA_URL_LENGTH) {
    throw new Error("音频文件过大，请选择较小文件");
  }
  return dataUrl;
}

function parseDataUrlMeta(dataUrl: string) {
  const matched = dataUrl.match(/^data:([a-z0-9.+-]+\/[a-z0-9.+-]+);base64,/i);
  if (!matched) return null;
  const mime = matched[1].toLowerCase();
  const extension = (() => {
    if (mime === "image/jpeg") return "jpg";
    if (mime === "image/png") return "png";
    if (mime === "image/webp") return "webp";
    if (mime === "image/gif") return "gif";
    if (mime === "image/bmp") return "bmp";
    if (mime === "image/svg+xml") return "svg";
    if (mime === "audio/mpeg") return "mp3";
    if (mime === "audio/mp3") return "mp3";
    if (mime === "audio/wav") return "wav";
    if (mime === "audio/x-wav") return "wav";
    if (mime === "audio/ogg") return "ogg";
    if (mime === "audio/aac") return "aac";
    if (mime === "audio/webm") return "webm";
    if (mime === "audio/mp4") return "m4a";
    if (mime === "application/pdf") return "pdf";
    if (mime === "text/plain") return "txt";
    if (mime === "text/csv") return "csv";
    if (mime === "application/json") return "json";
    if (mime === "application/zip") return "zip";
    if (mime === "application/x-zip-compressed") return "zip";
    if (mime === "application/x-rar-compressed") return "rar";
    if (mime === "application/x-7z-compressed") return "7z";
    if (mime === "application/msword") return "doc";
    if (mime === "application/vnd.openxmlformats-officedocument.wordprocessingml.document") return "docx";
    if (mime === "application/vnd.ms-excel") return "xls";
    if (mime === "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet") return "xlsx";
    if (mime === "application/vnd.ms-powerpoint") return "ppt";
    if (mime === "application/vnd.openxmlformats-officedocument.presentationml.presentation") return "pptx";
    const subtype = mime.split("/")[1] ?? "";
    const normalizedSubtype = subtype.split("+")[0]?.split(".").pop()?.replace(/[^a-z0-9]+/gi, "");
    return normalizedSubtype || "bin";
  })();
  return { mime, extension };
}

async function uploadDataUrlViaServerApi(
  dataUrl: string,
  merchantHint = "public",
  folder = "merchant-assets",
  usage = folder === "merchant-audio" ? "audio" : folder === "merchant-files" ? "support-file" : "generic-image",
): Promise<string | null> {
  try {
    const response = await fetch("/api/assets/upload", {
      method: "POST",
      headers: {
      "content-type": "application/json",
      },
      credentials: "same-origin",
      body: JSON.stringify({
        dataUrl,
        merchantHint,
        folder,
        usage,
      }),
    });
    if (!response.ok) return null;
    const payload = (await response.json().catch(() => null)) as { url?: unknown } | null;
    return typeof payload?.url === "string" && payload.url.trim() ? payload.url.trim() : null;
  } catch {
    return null;
  }
}

async function uploadDataUrlToSupabase(
  dataUrl: string,
  merchantHint = "public",
  folder = "merchant-assets",
  usage = folder === "merchant-audio" ? "audio" : folder === "merchant-files" ? "support-file" : "generic-image",
): Promise<string | null> {
  const meta = parseDataUrlMeta(dataUrl);
  if (!meta) return null;
  void meta;
  return uploadDataUrlViaServerApi(dataUrl, merchantHint, folder, usage);
}

async function uploadImageDataUrlToSupabase(
  dataUrl: string,
  merchantHint = "public",
  usage = "generic-image",
): Promise<string | null> {
  return uploadDataUrlToSupabase(dataUrl, merchantHint, "merchant-assets", usage);
}

async function uploadAudioDataUrlToSupabase(dataUrl: string, merchantHint = "public"): Promise<string | null> {
  return uploadDataUrlToSupabase(dataUrl, merchantHint, "merchant-audio", "audio");
}

function formatSupportAttachmentFileSize(bytes: number) {
  const normalized = Number.isFinite(bytes) ? Math.max(0, bytes) : 0;
  if (normalized >= 1024 * 1024) {
    return `${(normalized / (1024 * 1024)).toFixed(normalized >= 10 * 1024 * 1024 ? 0 : 1)} MB`;
  }
  if (normalized >= 1024) {
    return `${Math.max(1, Math.round(normalized / 1024))} KB`;
  }
  return `${normalized} B`;
}

