        const payload = await withTimeout(readMerchantSessionPayload(timeoutMs), timeoutMs, "商户身份识别超时，请稍后重试");
        if (!payload || payload.authenticated !== true) {
          return null;
        }
        const merchantIds = readMerchantSessionMerchantIds(payload);
